sys_script_include.script:
var AROP_CREATOR = Class.create();
AROP_CREATOR.prototype = {
    initialize: function() {
        this.module = 'CREATOR';
        this.utils  = new AROPUtils();
    },
    execute: function(runId) {
        gs.info('[AIROP] Starting CREATOR checks for run: ' + runId);
        var checks     = this.utils.getActiveChecks(this.module);
        var dateFilter = this.utils.getDateRangeFilter();
        var count      = 0;
        for (var i = 0; i < checks.length; i++) {
            var check = checks[i];
            try {
                var result = this._evalCheck(check, dateFilter);
                this.utils.storeResult(runId, check, result.status, result.actualValue, result.finding);
                count++;
                gs.info('[AIROP] ' + check.check_id + ' - ' + result.status);
            } catch(e) {
                gs.error('[AIROP] Error in check ' + check.check_id + ': ' + e.message);
                this.utils.storeResult(runId, check, 'needs_attention', 'Error: ' + e.message, 'Check execution error: ' + e.message);
                count++;
            }
        }
        gs.info('[AIROP] CREATOR complete - ' + count + ' checks executed');
        return count;
    },
    _evalCheck: function(checkDef, dateFilter) {
        var result = { status: 'needs_attention', actualValue: 'Check not evaluated', finding: 'Check not evaluated' };
        var handler = checkDef.check_id;
        if (!handler) {
            result.actualValue = 'No check_id defined';
            return result;
        }
        try {
            var lib = new AROPCheckLibrary_CREATOR();
            if (typeof lib[handler] !== 'function') {
                result.actualValue = 'Handler not found in AROPCheckLibrary_CREATOR: ' + handler;
                return result;
            }
            result = lib[handler]();
        } catch(e) {
            result.status      = 'needs_attention';
            result.actualValue = 'Handler error in ' + handler + ': ' + e.message;
            gs.error('[AIROP] Handler error ' + handler + ': ' + e.message);
        }
        return result;
    },
    type: 'AROP_CREATOR'
};
